// Synteleia Immunitas — git diff 取得 + 監査リクエスト生成
const { execSync } = require('child_process');
const fs = require('fs');

const HGK_DIR = '/home/makaron8426/Sync/oikos/01_ヘゲモニコン｜Hegemonikon';
const LOG_DIR = '/oikos/mneme/.hegemonikon/synteleia_logs';
const now = new Date();

try {
  // ログディレクトリ作成
  if (!fs.existsSync(LOG_DIR)) fs.mkdirSync(LOG_DIR, { recursive: true });

  // git diff 取得 (staged + unstaged)
  let diff = '';
  try {
    diff = execSync('git diff --stat && echo "---" && git diff --cached --stat', {
      cwd: HGK_DIR, encoding: 'utf-8', timeout: 10000
    });
  } catch(e) {
    diff = 'git diff failed: ' + e.message;
  }

  // 最新コミットの内容を取得
  let lastCommitDiff = '';
  try {
    lastCommitDiff = execSync('git log -1 --format="%H %s" && git diff HEAD~1..HEAD --stat', {
      cwd: HGK_DIR, encoding: 'utf-8', timeout: 10000
    });
  } catch(e) {
    lastCommitDiff = 'no recent commit diff';
  }

  // 変更がなければスキップ
  const hasDiff = diff.trim().length > 10 || lastCommitDiff.trim().length > 10;
  if (!hasDiff) {
    return [{ json: {
      timestamp: now.toISOString(),
      skipped: true,
      reason: 'no changes detected',
      auditNeeded: false
    }}];
  }

  // 監査対象テキストを構成
  const auditContent = [
    '## Git Changes (Uncommitted)',
    diff,
    '',
    '## Last Commit',
    lastCommitDiff
  ].join('\n');

  return [{ json: {
    timestamp: now.toISOString(),
    skipped: false,
    auditNeeded: true,
    auditContent: auditContent,
    diffLength: diff.length,
    source: 'wf16-immunitas-cron'
  }}];

} catch(e) {
  return [{ json: {
    timestamp: now.toISOString(),
    skipped: true,
    error: e.message,
    auditNeeded: false
  }}];
}

// 監査結果を解析し、アラート要否を判定
const fs = require('fs');
const LOG_DIR = '/oikos/mneme/.hegemonikon/synteleia_logs';
const now = new Date();
const result = $input.first().json;

// 監査ログを保存 (Layer C: Pronoia のためのデータ蓄積)
const logFile = LOG_DIR + '/audit_' + now.toISOString().replace(/[:.]/g, '-') + '.json';
try {
  if (!fs.existsSync(LOG_DIR)) fs.mkdirSync(LOG_DIR, { recursive: true });
  fs.writeFileSync(logFile, JSON.stringify(result, null, 2), 'utf-8');
} catch(e) {
  // ログ保存失敗はアラートに影響しない
}

const criticalCount = result.critical_count || 0;
const highCount = result.high_count || 0;
const totalIssues = result.total_issues || 0;
const passed = result.passed !== false;

const shouldAlert = criticalCount > 0 || highCount > 0;

let notifPayload = '';
if (shouldAlert) {
  const emoji = criticalCount > 0 ? '🚨🛡️' : '⚠️🛡️';
  const lines = [
    emoji + ' Synteleia Immunitas: ' + totalIssues + ' issues detected',
    '',
    '🔴 Critical: ' + criticalCount,
    '🟠 High: ' + highCount,
    '📊 Total: ' + totalIssues,
    '',
    '📋 Summary: ' + (result.summary || 'N/A'),
  ];

  // エージェント別の結果
  if (resultnous_results) {
    lines.push('');
    lines.push('--- Agent Results ---');
    for (const ar of resultnous_results) {
      const icon = ar.passed ? '✅' : '❌';
      lines.push(icon + ' ' + arnous_name + ' (' + Math.round(ar.confidence * 100) + '%)');
      if (ar.issues && ar.issues.length > 0) {
        for (const iss of ar.issues.slice(0, 3)) {
          lines.push('  → [' + iss.severity + '] ' + iss.message);
        }
      }
    }
  }

  notifPayload = lines.join('\n');
}

return [{ json: {
  timestamp: now.toISOString(),
  passed,
  shouldAlert,
  criticalCount,
  highCount,
  totalIssues,
  notifPayload,
  logFile,
  report: result.report || ''
}}];
